def subscribe(event_class_or_name, handler_method = nil, &block)
  handler = handler_method || block
  raise ArgumentError, 'Handler required' unless handler
  if event_class_or_name.is_a?(String)
    @subscribers[event_class_or_name] << handler
  else
    unless event_class_or_name < Events::BaseEvent
      raise ArgumentError, "Expected an Event class, got #{event_class_or_name}"
    end
    @subscribers[event_class_or_name] << handler
  end
end

def publish(event_or_name, payload = nil)
  if event_or_name.is_a?(String)
    event = Events::BaseEvent.new(name: event_or_name, payload: payload || {})
    @subscribers[event_or_name].each { |h| h.call(event.payload) }
  else
    raise ArgumentError unless event_or_name.is_a?(Events::BaseEvent)
    event = event_or_name
    @subscribers[event.class].each { |h| h.call(event) }
  end
  logger.info("Published #{event.name}")
